function getBodyPerkDescription(perk, tier) {
    var cls = gameState.selectedClass;
    if (cls && classAdaptations[cls] && classAdaptations[cls].bodyPerks[perk] && classAdaptations[cls].bodyPerks[perk][tier]) {
        return classAdaptations[cls].bodyPerks[perk][tier];
    }
    if (typeof bodyPerkTiers !== 'undefined' && bodyPerkTiers[perk] && bodyPerkTiers[perk][tier]) {
        return bodyPerkTiers[perk][tier];
    }
    return 'Tier ' + tier + ': Description not available.';
}

